member.example:
Bind the Transform rotation using a serialized binder field — the target Transform is assigned in the Inspector.

    [View]
    public partial class ExampleView
    {
        [SerializeField]
        private TransformRotationBinder _rotation;
    }
    
    [ViewModel]
    public partial class ExampleViewModel
    {
        [Bind] public Quaternion _rotation;
    }


Bind the Transform rotation by constructing the binder in code.

    [View]
    public partial class ExampleView
    {
        [SerializeField] private Transform _target;
        
        private TransformRotationBinder Rotation =>
            new(_target);
    }
    
    [ViewModel]
    public partial class ExampleViewModel
    {
        [Bind] public Quaternion _rotation;
    }

Switch the Transform rotation between two euler angle values using a serialized binder field — the target Transform is assigned in the Inspector.

    [View]
    public partial class ExampleView
    {
        [SerializeField]
        private TransformRotationSwitcherBinder _isRotated;
    }
    
    [ViewModel]
    public partial class ExampleViewModel
    {
        [Bind] public bool _isRotated;
    }


Switch the Transform rotation between two euler angle values by constructing the binder in code.

    [View]
    public partial class ExampleView
    {
        [SerializeField]
        private Transform _target;
        
        [SerializeField]
        private Vector3 _rotatedEuler;
        
        [SerializeField]
        private Vector3 _defaultEuler;
        
        private TransformRotationSwitcherBinder IsRotated => new(
            _target, _rotatedEuler, _defaultEuler);
    }
    
    [ViewModel]
    public partial class ExampleViewModel
    {
        [Bind] public bool _isRotated;
    }
